    MatchCoord * result = MATCH_BASE(match_coords, qryid);

    SHIFT_QUERIES(queries, qryAddr);

    int last = qlen - min_match_len;
    for (int qrystart = 0;
             qrystart <= last;
             qrystart++, 
             result += RESULT_SPAN) 
    {
