        unsigned int refpos = 0;
        while ((c != '\0')) 
        {
            _PixelOfChildren children;
            children.data = GETCHILDRENHIST(cur, false);
            prev = cur;
            uchar3 next;
            switch (c) 
            {
                case 'A': next = children.a; break;
                case 'C': next = children.c; break;
                case 'G': next = children.g; break;
                case 'T': next = children.t; break;
                default: next.x = 0; next.y = 0; next.z = 0; break;
            };

            arrayToAddress_k(next, cur);

            if (cur == 0) {
                SET_RESULT(prev, result, 0, qry_match_len, min_match_len, FORWARD);

                qry_match_len -= 1;
                mustmatch = 0;

                goto NEXT_SUBSTRING;
            }

            _PixelOfNode node;
            node.data = GETNODEHIST(cur, true);
            node_start = (unsigned int)MKI(node.start);
            unsigned int node_end = (unsigned int)MKI(node.end);

            {
                int edgelen = (int)node_end - (int)node_start + 1;
                int edge_matchlen = (int)node_start + mustmatch;
                int past_node_end = (int)node_end + 1;
                int dist_to_edge_end = mustmatch - edgelen;
                if (mustmatch) {
                    refpos = (unsigned int)imin_k(edge_matchlen, past_node_end);
                    qry_match_len += imin_k(edgelen, mustmatch);
                    mustmatch = imax_k(dist_to_edge_end, 0);
                }
                else {
                    qry_match_len++;
                    refpos = node_start + 1;
                }
            }

            c = GETQCHAR(qrystart + qry_match_len);

            while (refpos <= node_end && c != '\0') 
            {
                char r = GETRCHAR((int)refpos);

                if (r != c) 
                {
                    goto RECORD_RESULT;
                }

                qry_match_len++;
                refpos++;

                c = GETQCHAR(qrystart + qry_match_len);
            }
        }

RECORD_RESULT:
        {
            SET_RESULT(cur, result, (int)refpos - (int)node_start, qry_match_len,
                       min_match_len, FORWARD);

            mustmatch = (int)refpos - (int)node_start;
            qry_match_len -= mustmatch + 1;
        }
NEXT_SUBSTRING:
        {
            _PixelOfNode node;
            node.data = GETNODEHIST(prev, false);
            arrayToAddress_k(node.suffix, cur);
        }
        do {} while (0);
    }

    return;
}

