#include <iostream>
using namespace std;

inline int max2(int a, int b)
{
  return (a > b) ? a : b;
}

inline int max4(int a, int b, int c, int d)
{
  int maxl = (a > b) ? a : b;
  int maxr = (c > d) ? c : d;

  return (maxl > maxr) ? maxl : maxr;
}

int s(char a, char b, int match_score, int mismatch_score)
{
  if (a == b)
  {
    return match_score;
  }

  return mismatch_score;
}

struct aligned_t
{
  char s;
  char t;
  int score;
};
typedef struct aligned_t aligned_t;



void align(const string & S, 
           const string & T,
           int match_score,
           int mismatch_score,
           int gap_open,
           int gap_extension)
{
  int m = S.length()-1;
  int n = T.length()-1;

  int E[m+2][n+2];
  int F[m+2][n+2];
  int G[m+2][n+2];
  int V[m+2][n+2];


  for (int i = 0; i <= m; i++)
  {
    E[i][0] = 0;
    F[i][0] = 0;
    G[i][0] = 0;
    V[i][0] = E[i][0];
  }

  for (int j = 0; j <= n; j++)
  {
    F[0][j] = 0;
    E[0][j] = 0;
    G[0][j] = 0;
    V[0][j] = F[0][j];
  }

  G[0][0] = 0;
  V[0][0] = 0;

  int maxi = 0;
  int maxj = 0;
  int maxv = 0;

  for (int i = 1; i <= m; i++)
  {
    for (int j = 1; j <= n; j++)
    {
      E[i][j] = max2(E[i-1][j] - gap_extension,
                     V[i-1][j] - gap_open - gap_extension);

      F[i][j] = max2(F[i-1][j] - gap_extension,
                     V[i-1][j] - gap_open - gap_extension);

      G[i][j] = V[i-1][j-1] + s(S[i], T[j], match_score, mismatch_score);

      V[i][j] = max4(E[i][j], F[i][j], G[i][j], 0);

      if (V[i][j] > maxv)
      {
        maxv = V[i][j];
        maxi = i;
        maxj = j;
      }
    }
  }

  aligned_t trace[m+n+2];
  int i = maxi, j = maxj;
  int tlen = 0;

  while (i > 0 && j > 0)
  {
    int v = V[i][j];
    trace[tlen].score = v;

    if (v == G[i][j])
    {
      trace[tlen].s = S[i];
      trace[tlen].t = T[j];
      i--;
      j--;
    }
    else if (v == E[i][j])
    {
      trace[tlen].s = S[i];
      trace[tlen].t = '-';
      i--;
    }
    else if (v == F[i][j])
    {
      trace[tlen].s = '-';
      trace[tlen].t = T[j];
      j--;
    }
    else
    {
      break;
    }

    tlen++;
  }
}
